// Auto-Clicker Pro
function autoClick(interval = 1000) {
  setInterval(() => {
    document.elementFromPoint(x, y).click();
  }, interval);
}
// Usage: autoClick(500); // Clicks every 500ms

// Game Speed Modifier
function setGameSpeed(speed = 2.0) {
  Object.defineProperty(window, 'gameSpeed', {
    value: speed,
    writable: true
  });
  console.log(`Game speed set to ${speed}x`);
}

// Force Dark Mode
(function() {
  const style = document.createElement('style');
  style.textContent = `
    * { background-color: #1a1a1a !important; color: #e0e0e0 !important; }
    img, video { opacity: 0.8; }
  `;
  document.head.appendChild(style);
})();

// XP Multiplier
const originalXP = window.gainXP;
window.gainXP = function(amount) {
  const multiplier = 5; // 5x XP
  return originalXP(amount * multiplier);
};

// Form Autofill
function autofillForms() {
  const inputs = document.querySelectorAll('input');
  inputs.forEach(input => {
    if(input.type === 'email') input.value = 'test@test.com';
    if(input.type === 'text') input.value = 'Test User';
    if(input.type === 'password') input.value = 'password123';
  });
}

